('Banana Crush', 'banana-crush', 'indica', 16.4, 0.2, array['sleepy', 'uplifted', 'euphoric']::text[], array['skunk', 'pine', 'woody']::text[], array['caryophyllene', 'ocimene', 'myrcene']::text[], 'easy', 7, '500-600 g/m²', '500-650 g/plant', 'Banana Crush — An indica known for deep body relaxation, best reserved for evenings and lazy nights in. Expect skunk, pine, woody flavors with dominant caryophyllene, most often leaving users feeling sleepy and uplifted.')
